('VMS_2019_consolidated', 'VMS', 2019, 'consolidated', 'Công ty TNHH Kiểm toán và Thẩm định giá Việt Nam', 'unqualified', 0, NULL),
('VMS_2017_consolidated', 'VMS', 2017, 'consolidated', 'Công ty TNHH KPMG Việt Nam', 'unqualified', 0, NULL),
('VMS_2015_consolidated', 'VMS', 2015, 'consolidated', 'Công ty TNHH Kiểm toán Nhân Tâm Việt', 'unqualified', 0, NULL),
('VMK_2024_consolidated', 'VMK', 2024, 'consolidated', 'Chi nhánh Hà Nội - Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VMG_2024_consolidated', 'VMG', 2024, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'qualified', 1, 'Tại ngày 31/12/2024, các khoản nợ ngắn hạn của Công ty đã vượt quá tài sản ngắn hạn với số tiền là 5.685.301.990 VND, đồng thời, Công ty có khoản lỗ lũy kế với số tiền là 121.279.230.672 VND. Trong năm tài chính kết thúc cùng ngày, Công ty có kết quả kinh doanh lỗ với số tiền là 6.401.386.128 VND.'),
('VMG_2025_consolidated', 'VMG', 2025, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'unqualified', 1, 'Tại ngày 31/12/2025, Nợ ngắn hạn của Công ty đã vượt quá tài sản ngắn hạn với số tiền là 21.529.729.627 VND. Công ty đang chịu một khoản lỗ lũy kế đến ngày 31/12/2025 với số tiền là 147.426.723.246 VND, đồng thời khoản lỗ lũy kế này đã làm âm Vốn chủ sở hữu với số tiền là 12.868.769.704 VND. Những điều kiện này cho thấy sự tồn tại yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục của Công ty.'),
('VMG_2022_consolidated', 'VMG', 2022, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'qualified', 1, 'Tại ngày 31/12/2022, các khoản nợ ngắn hạn của Công ty vượt quá tài sản ngắn hạn số tiền 44.274.954.657 VND. Công ty có kết quả kinh doanh lỗ 28.970.660 VND và lưu chuyển tiền thuần từ hoạt động kinh doanh âm 11.276.526.375 VND. Công ty đang chịu khoản lỗ lũy kế 115.431.170.995 VND. Khả năng tiếp tục hoạt động trong vòng 12 tháng tới phụ thuộc vào khả năng tạo ra dòng tiền và tìm kiếm các khoản vay dài hạn.'),
('VMG_2021_consolidated', 'VMG', 2021, 'consolidated', 'Công ty TNHH Kiểm toán CPA VIETNAM', 'qualified', 1, 'Tại ngày 31/12/2021, nợ ngắn hạn của Công ty đã vượt tài sản ngắn hạn với số tiền 43.065.009.895 VND. Lưu chuyển tiền thuần trong năm âm 2.681.352.138 VND. Khả năng tiếp tục hoạt động trong vòng 12 tháng tới phụ thuộc vào khả năng tạo ra dòng tiền và tìm kiếm các khoản vay dài hạn.');
INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VMG_2020_consolidated', 'VMG', 2020, 'consolidated', 'Công ty TNHH Kiểm toán - Tư vấn Đất Việt', 'qualified', 1, 'Khoản lỗ lũy kế tại ngày 31 tháng 12 năm 2020 là 100.496.058.302 VND và nợ ngắn hạn vượt tài sản ngắn hạn 30.681.410.765 VND, dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục.'),
('VMG_2019_consolidated', 'VMG', 2019, 'consolidated', 'Công ty TNHH Kiểm toán - Tư vấn Đất Việt (Vietland)', 'qualified', 1, 'Khoản lỗ lũy kế của Công ty tại ngày 31/12/2019 là 95.751.492.840 VND và nợ ngắn hạn đã vượt hơn tài sản ngắn hạn 9.868.174.673 VND, dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục.'),
('VMG_2018_consolidated', 'VMG', 2018, 'consolidated', 'Công ty TNHH Kiểm toán - Tư vấn Đất Việt', 'qualified', 1, 'Khoản lỗ lũy kế tại ngày 31 tháng 12 năm 2018 là 91.392.770.080 VND và cũng tại ngày này, nợ ngắn hạn của Công ty đã vượt hơn tài sản ngắn hạn một khoản là 23.844.312.516 VND. Vì vậy, khả năng tiếp tục hoạt động của Công ty phụ thuộc vào khả năng tạo ra nguồn tiền từ hoạt động kinh doanh và sự hỗ trợ tài chính từ chủ đầu tư của Công ty.'),
('VMG_2017_consolidated', 'VMG', 2017, 'consolidated', 'Công ty TNHH Kiểm toán - Tư vấn Đất Việt', 'qualified', 1, 'Khoản lỗ lũy kế tại ngày 31 tháng 12 năm 2017 cao và cũng tại ngày này, nợ ngắn hạn của Công ty đã vượt hơn tài sản ngắn hạn. Vì vậy, khả năng tiếp tục hoạt động của Công ty phụ thuộc vào khả năng tạo ra nguồn tiền từ hoạt động kinh doanh của Công ty.'),
('VMG_2016_consolidated', 'VMG', 2016, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn Đất Việt (Vietland)', 'qualified', 1, 'Khoản lỗ lũy kế tại ngày 31/12/2016 là 95.393.010.460 VND; nợ ngắn hạn vượt hơn tài sản ngắn hạn 18.614.838.854 VND. Khả năng tiếp tục hoạt động của Công ty phụ thuộc vào khả năng tạo ra nguồn tiền từ hoạt động kinh doanh.'),
('VMG_2015_consolidated', 'VMG', 2015, 'consolidated', 'Công ty TNHH Kiểm toán FAC', 'qualified', 1, 'Tại ngày 31/12/2015, tổng nợ phải trả ngắn hạn vượt quá tổng tài sản ngắn hạn 14.472.174.883 VND, khoản lỗ lũy kế là 89.676.463.461 VND chiếm 93% vốn điều lệ. Sự tồn tại không chắc chắn trọng yếu về khả năng Công ty tiếp tục hoạt động liên tục. Công ty phụ thuộc vào việc thu được lợi nhuận từ hoạt động trong tương lai hoặc thu xếp nguồn tài chính để trả nợ.'),
