('VKC_2025_consolidated', 'VKC', 2025, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn Chuẩn Việt', 'disclaimer', 1, 'Tại ngày 31/12/2025, Công ty có khoản lỗ lũy kế sau thuế chưa phân phối là (511.326.921.089) đồng; khoản nợ ngắn hạn (526.632.058.999 đồng) lớn hơn tài sản ngắn hạn của Công ty (177.825.822.434 đồng) với số tiền là 348.806.236.565 đồng; các khoản nợ phải trả nợ vay, trái phiếu và lãi tiền vay, trái phiếu đã quá hạn thanh toán với tổng số tiền là 516.422.072.160 đồng và vốn chủ sở hữu âm (290.196.738.243 đồng).');
INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VKC_2024_consolidated', 'VKC', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn Chuẩn Việt', 'disclaimer', 1, 'Các điều kiện này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động kinh doanh liên tục của Công ty.'),
('VJC_2025_parent', 'VJC', 2025, 'parent', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VJC_2025_consolidated', 'VJC', 2025, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VJC_2024_consolidated', 'VJC', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VJC_2023_consolidated', 'VJC', 2023, 'consolidated', 'Công ty TNHH PwC (Việt Nam)', 'unqualified', 0, NULL),
('VJC_2024_parent', 'VJC', 2024, 'parent', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VJC_2022_consolidated', 'VJC', 2022, 'consolidated', 'Công ty TNHH PwC (Việt Nam)', 'unqualified', 0, NULL),
('VJC_2022_parent', 'VJC', 2022, 'parent', 'Công ty TNHH PwC (Việt Nam)', 'unqualified', 0, NULL),
('VJC_2021_consolidated', 'VJC', 2021, 'consolidated', 'Công ty TNHH PwC (Việt Nam)', 'unqualified', 0, NULL),
('VJC_2021_parent', 'VJC', 2021, 'parent', 'Công ty TNHH PwC (Việt Nam)', 'unqualified', 0, NULL),
('VJC_2020_consolidated', 'VJC', 2020, 'consolidated', 'Công ty TNHH PwC (Việt Nam)', 'unqualified', 1, 'Sự tồn tại của yếu tố không chắc chắn trọng yếu do ảnh hưởng của dịch COVID-19 đến hoạt động kinh doanh và dòng tiền của Tập đoàn, khiến việc đánh giá về hoạt động liên tục phụ thuộc vào khả năng tạo ra đủ tiền từ hoạt động kinh doanh và các giải pháp khác.'),
('VJC_2020_parent', 'VJC', 2020, 'parent', 'Công ty TNHH PwC (Việt Nam)', 'unqualified', 1, 'Sự lan rộng của dịch COVID-19 đã ảnh hưởng nghiêm trọng đến hoạt động kinh doanh vận tải hàng không, dẫn đến lỗ gộp và dòng tiền giảm sút. Các yếu tố không chắc chắn về khả năng phục hồi nhu cầu đi lại và quy định hạn chế đi lại tạo ra rủi ro trọng yếu đối với giả định hoạt động liên tục.'),
('VJC_2019_consolidated', 'VJC', 2019, 'consolidated', 'Công ty TNHH KPMG Việt Nam', 'unqualified', 1, 'Đại dịch COVID-19 tác động nghiêm trọng đến hoạt động kinh doanh hàng không. Giá trị giả định hoạt động liên tục phụ thuộc vào khả năng tạo đủ dòng tiền từ vận tải hàng không và tài chính thương mại tàu bay. Các quy định hạn chế đi lại quốc gia và sự phục hồi nhu cầu đi lại đường hàng không cho thấy sự tồn tại yếu tố không chắc chắn có thể ảnh hưởng quan trọng đến khả năng hoạt động liên tục.'),
('VJC_2019_parent', 'VJC', 2019, 'parent', 'Chi nhánh Công ty TNHH KPMG tại Thành phố Hồ Chí Minh', 'unqualified', 1, 'Ý kiến kiểm toán không bị thay đổi. Kiểm toán viên lưu ý người đọc về Thuyết minh 38 về ảnh hưởng của dịch COVID-19 đến tình hình hoạt động kinh doanh sau niên độ. Giá trị của giả định hoạt động liên tục cơ bản phụ thuộc vào khả năng Công ty tạo ra đủ dòng tiền từ hoạt động kinh doanh vận tải hàng không và tài chính thương mại tàu bay. Sự ảnh hưởng của các quy định hạn chế đi lại và sự phục hồi nhu cầu đi lại bằng đường hàng không cho thấy sự tồn tại của yếu tố không chắc chắn có thể ảnh hưởng quan trọng đến khả năng hoạt động liên tục.'),
('VJC_2018_parent', 'VJC', 2018, 'parent', 'Công ty TNHH KPMG Việt Nam', 'unqualified', 0, NULL),
('VJC_2018_consolidated', 'VJC', 2018, 'consolidated', 'Công ty TNHH KPMG Việt Nam', 'unqualified', 0, NULL),
('VJC_2017_consolidated', 'VJC', 2017, 'consolidated', 'Công ty TNHH KPMG Việt Nam', 'unqualified', 0, NULL),
('VJC_2017_parent', 'VJC', 2017, 'parent', 'Công ty TNHH KPMG Việt Nam', 'unqualified', 0, NULL),
('VJC_2016_consolidated', 'VJC', 2016, 'consolidated', 'Công ty TNHH KPMG', 'unqualified', 0, NULL),
('VJC_2016_parent', 'VJC', 2016, 'parent', 'Công ty TNHH KPMG Việt Nam', 'unqualified', 0, NULL);
