INSERT OR REPLACE INTO `audit_reports` (`id`, `ticker`, `year`, `report_type`, `auditor_name`, `audit_opinion`, `going_concern_issue`, `going_concern_detail`) VALUES
('VIW_2017_consolidated', 'VIW', 2017, 'consolidated', 'Công ty TNHH Kiểm toán An Việt', 'qualified', 1, 'Có nhiều vấn đề ảnh hưởng đến khả năng hoạt động liên tục: Công ty con Viwaseen.1 chưa ghi nhận khoản nợ thuế hơn 9.6 tỷ đồng; Công ty con Viwaseen.2 có sai lệch số dư thuế GTGT phải nộp; Không hợp nhất được Công ty Viwaseen.15 do tạm dừng hoạt động; Nhiều khoản phải thu, phải trả và chi phí sản xuất dở dang chưa được đối chiếu, xác nhận đầy đủ; Chưa hoàn tất quyết toán cổ phần hóa.'),
('VIW_2015_consolidated', 'VIW', 2015, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'qualified', 0, NULL),
('VIT_2025_consolidated', 'VIT', 2025, 'consolidated', 'Công ty TNHH Kiểm toán Deloitte Việt Nam', 'unqualified', 0, NULL),
('VIT_2024_consolidated', 'VIT', 2024, 'consolidated', 'Công ty TNHH Kiểm toán Deloitte Việt Nam', 'unqualified', 0, NULL),
('VIT_2023_consolidated', 'VIT', 2023, 'consolidated', 'Công ty TNHH Kiểm toán Deloitte Việt Nam', 'unqualified', 0, NULL),
('VIT_2022_consolidated', 'VIT', 2022, 'consolidated', 'Công ty TNHH Kiểm toán Deloitte Việt Nam', 'unqualified', 0, NULL),
('VIT_2020_consolidated', 'VIT', 2020, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 1, 'Tại ngày 31/12/2020, Nợ ngắn hạn đã vượt quá Tài sản ngắn hạn là 41,09 tỷ VND. Công ty lập BCTC dựa trên giả định hoạt động liên tục do: (1) Tình hình xuất phát từ việc huy động vốn vay lớn đầu tư Nhà máy Viglacera Mỹ Đức đang dần phát huy hiệu quả; (2) Đại hội đồng Cổ đông thông qua phương án tăng vốn điều lệ từ 195 tỷ lên 500 tỷ đồng; (3) Công ty là công ty con của Tổng công ty Viglacera - CTCP nên được đảm bảo hỗ trợ tài chính.'),
('VIT_2021_consolidated', 'VIT', 2021, 'consolidated', 'Công ty TNHH Deloitte Việt Nam', 'unqualified', 0, NULL),
('VIT_2019_consolidated', 'VIT', 2019, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VIT_2018_consolidated', 'VIT', 2018, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VIT_2016_consolidated', 'VIT', 2016, 'consolidated', 'Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VIT_2017_consolidated', 'VIT', 2017, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VIT_2015_consolidated', 'VIT', 2015, 'consolidated', 'Công ty TNHH Hãng Kiểm toán AASC', 'unqualified', 0, NULL),
('VISECO_2025_consolidated', 'VISECO', 2025, 'consolidated', 'Công ty TNHH Kiểm toán và Dịch vụ Tin học MOORE AISC', 'unqualified', 0, NULL),
('VISECO_2023_consolidated', 'VISECO', 2023, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 1, 'Năm 2023, Công ty tiếp tục bị lỗ 4.593.950.015 đồng, khoản lỗ lũy kế đến ngày 31/12/2023 là 13.697.508.353 đồng, lưu chuyển tiền thuần từ hoạt động kinh doanh tiếp tục bị âm. Các yếu tố này cho thấy sự tồn tại của yếu tố không chắc chắn trọng yếu có thể dẫn đến nghi ngờ đáng kể về khả năng hoạt động liên tục. Công ty đã có phương án tăng vốn điều lệ từ 37.500.000.000 đồng lên mức 337.500.000.000 đồng và Ban Tổng Giám đốc tiếp tục thực hiện các biện pháp quản lý chặt chẽ, xây dựng kế hoạch kinh doanh hợp lý.'),
('VISECO_2021_consolidated', 'VISECO', 2021, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY - Chi nhánh Miền Trung', 'unqualified', 0, NULL),
('VISECO_2024_consolidated', 'VISECO', 2024, 'consolidated', 'Công ty TNHH Kiểm toán và Dịch vụ tin học MOORE AISC', 'qualified', 0, NULL),
('VISECO_2020_consolidated', 'VISECO', 2020, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY – Chi nhánh Miền Trung', 'unqualified', 0, NULL),
('VISECO_2018_consolidated', 'VISECO', 2018, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY', 'unqualified', 0, NULL),
('VISECO_2019_consolidated', 'VISECO', 2019, 'consolidated', 'Công ty TNHH Kiểm toán và Tư vấn UHY – Chi nhánh Miền Trung', 'unqualified', 0, NULL);
